        int len = s.length();
        for (int index = 0; index < len; index++) {
            char c = s.charAt(index);
            if (len == 1 && c == '0') return false;
            if (c == '0' && s.length() > 1) return false;
            if (c < '0' || c > '9') {
                 return false;
            }
        }
        return true;
    }

